arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: throws in EF Core 9 Cosmos provider.
    // Manage indexing via the container's indexing policy in Azure Portal/Bicep.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name ("Discriminator" → not "$type")
        // so existing 500K documents remain queryable, including direct SQL on c.Discriminator.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123") so existing documents
        // are still found by FindAsync / point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

