     public DbSet<Product> Products => Set<Product>();
     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         // HasIndex removed: throws in EF Core 9 Cosmos provider.
         // Manage indexing via the container's indexing policy in Azure Portal/Bicep.

         modelBuilder.Entity<Product>(entity =>
         {
             entity.ToContainer("Products");

             // Preserve EF Core 8 discriminator property name ("Discriminator" → not "$type")
