             entity.HasDiscriminator<string>("Discriminator");

             // Preserve EF Core 8 compound id format ("Product|123") so existing documents
             // are still found by FindAsync / point-reads.
             entity.HasRootDiscriminatorInJsonId(true);
         });
     }
 }
